import { PublicActionPage } from '@domain/publicActionPage';
import { ChangeEvent } from 'react';
import { Controller, useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { getFieldNames } from '../AddressControl/getFieldNames';
import { SmartyAddressInput, SmartyAddressInputProps } from './SmartyAddressInput';
import { SmartyAddress } from './types';

export const FormSmartyAddressInput = ({
  actionPage,
  fieldPrefix,
  fieldPrefixDelimiter,
  ...props
}: Partial<SmartyAddressInputProps> & {
  actionPage?: PublicActionPage;
  fieldPrefix: string | undefined;
  fieldPrefixDelimiter: string | undefined;
}) => {
  const { t } = useTranslation('formControls');
  const { control, resetField, setValue } = useFormContext();

  const { fieldCity, fieldCountry, fieldLine1, fieldLine2, fieldPostalCode, fieldRegion } =
    getFieldNames(fieldPrefix, fieldPrefixDelimiter);

  const onSelectAddress = (address: SmartyAddress) => {
    resetField(fieldLine1);
    setValue(fieldLine1, address.street_line, { shouldTouch: true });
    setValue(fieldLine2, address.secondary, { shouldTouch: true, shouldValidate: true });
    setValue(fieldCity, address.city, { shouldTouch: true, shouldValidate: true });
    setValue(fieldRegion, address.state, { shouldTouch: true, shouldValidate: true });
    setValue(fieldPostalCode, address.zipcode, { shouldTouch: true, shouldValidate: true });
    // Smarty US Autocomplete Pro API is for US addresses only (no international addresses)
    setValue(fieldCountry, 'US', { shouldTouch: true, shouldValidate: true });
  };

  const onChange = (e: ChangeEvent<HTMLInputElement>) => {
    setValue(fieldLine1, e.target.value, { shouldValidate: true });
  };

  return (
    <Controller
      control={control}
      name={fieldLine1}
      render={({ field: { ...rest }, fieldState: { error, invalid } }) => (
        <SmartyAddressInput
          actionPage={actionPage}
          label={props.label || t('formAddressControl.streetAddress')}
          {...rest}
          {...props}
          formControlProps={{
            error: error?.message,
            isInvalid: invalid,
          }}
          isInvalid={invalid}
          onChange={onChange}
          onSelectAddress={onSelectAddress}
          placeholder={t('formAddressControl.enterALocation')}
          testid="address-input"
        />
      )}
    />
  );
};

